onClick:
CreatePreference.run()
  .then((prefRes) => {
    const preferenceId = prefRes?.id || prefRes?.data?.id;

    if (!preferenceId) {
      throw new Error("CreatePreference did not return a preference id");
    }

    return storeValue("buildTitle", BuildTitle.text || "My First Build")
      .then(() => storeValue("preferenceId", preferenceId))
      .then(() =>
        CreateBuild.run({
          preferenceId: preferenceId
        })
      );
  })
  .then((buildRes) => {
    const buildId = buildRes?.id || buildRes?.data?.id;

    if (!buildId) {
      throw new Error("CreateBuild did not return a build id");
    }

    return storeValue("selectedBuildId", buildId)
      .then(() => GetAllBuilds.run())
      .then(() => navigateTo("Results"));
  })
  .catch((err) => {
    showAlert("Failed to save preferences or generate build", "error");
    console.log("Combined save/build error:", err);
  })
